import axios from 'axios';

// API URL - localhost for development
export const API_URL = 'http://localhost:8000/api';

console.log('🔗 API URL:', API_URL);

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  timeout: 30000,
  headers: {
    'Content-Type': 'application/json',
  },
  withCredentials: false,
});

// Request interceptor - add auth token
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    console.log(`📤 ${config.method?.toUpperCase()} ${config.url}`);
    return config;
  },
  (error) => {
    console.error('Request error:', error);
    return Promise.reject(error);
  }
);

// Response interceptor - handle errors
api.interceptors.response.use(
  (response) => {
    console.log(`📥 ${response.status} ${response.config.url}`);
    return response;
  },
  (error) => {
    console.error('API Error:', error.response?.status, error.message);
    
    // Handle 401 - Unauthorized (but don't auto-redirect)
    if (error.response?.status === 401) {
      console.log('🔒 Unauthorized - token might be invalid');
    }
    
    return Promise.reject(error);
  }
);

// ============================================
// AUTH API
// ============================================
export const authAPI = {
  login: async (email, password) => {
    const response = await api.post('/auth/login', { email, password });
    return response.data;
  },
  
  register: async (userData) => {
    const response = await api.post('/auth/register', userData);
    return response.data;
  },
  
  getMe: async () => {
    const response = await api.get('/auth/me');
    return response.data;
  },
  
  verify: async () => {
    const response = await api.get('/auth/verify');
    return response.data;
  }
};

// ============================================
// PREDICTION API
// ============================================
export const predictSign = async (imageBase64, expectedLetter = null) => {
  try {
    console.log('🤖 Calling prediction API...');
    const response = await api.post('/predict/', {
      image: imageBase64,
      expected: expectedLetter
    });
    console.log('✅ Prediction response:', response.data);
    return response.data;
  } catch (error) {
    console.error('❌ Prediction failed:', error);
    return {
      success: false,
      error: error.response?.data?.detail || error.response?.data?.error || error.message,
      handDetected: false
    };
  }
};

// Check model health
export const checkModelHealth = async () => {
  try {
    const response = await api.get('/predict/health');
    return response.data;
  } catch (error) {
    console.error('Model health check failed:', error);
    return { status: 'unavailable' };
  }
};

// Get available classes
export const getClasses = async () => {
  try {
    const response = await api.get('/predict/classes');
    return response.data;
  } catch (error) {
    console.error('Get classes failed:', error);
    return { classes: [], count: 0 };
  }
};

export default api;
